import{_ as e,o as a,c as i,e as t}from"./app-4259075f.js";const r="/assets/image-1-3021f6ec.png",l="/assets/image-d3e26696.png",o="/assets/image-2-8f1fe9ff.png",s={},d=t('<p>参考链接：https://learnku.com/articles/41728</p><h2 id="gmp-模型" tabindex="-1"><a class="header-anchor" href="#gmp-模型" aria-hidden="true">#</a> GMP 模型</h2><p><img src="'+r+'" alt="Alt text"></p><ul><li>G: goroutine, 协程, 内存占用小, 切换速度快（切换在用户态完成）</li><li>M: machine thread, 内核线程</li><li>P: processor, goroutine 调度器, 将可运行的 goroutine 分配到工作线程上</li><li>P 的本地队列: 存放等待运行的 G, 存放的数量有限制, 不超过 256 个</li><li>P 列表: 所有的 P 在程序启动时创建, 保存在数组中，数量通过 <code>GOMAXPROCS</code> 参数配置</li><li>全局队列: 存放等待运行的 G</li></ul><h2 id="调度器的设计策略" tabindex="-1"><a class="header-anchor" href="#调度器的设计策略" aria-hidden="true">#</a> 调度器的设计策略</h2><h3 id="复用线程" tabindex="-1"><a class="header-anchor" href="#复用线程" aria-hidden="true">#</a> 复用线程</h3><ol><li><p>work stealing 机制: 当本地线程 M 没有可执行的 G 时, M 会尝试从全局队列中拿一部分 G 放到与之绑定的P, 或者与之绑定的 P 尝试从其他 P 的本地队列中偷取一半的 G 到自己的本地队列中</p></li><li><p>hand off 机制: 当本地线程 M 因 G 进行系统调用而阻塞, M 会释放绑定的 P, 将 P 转移给空闲的线程执行, 如果没有就创建新的线程</p></li></ol><h3 id="利用并行" tabindex="-1"><a class="header-anchor" href="#利用并行" aria-hidden="true">#</a> 利用并行</h3><p>通过 <code>GOMAXPROCS</code> 设置 P 的数量，最多有 <code>GOMAXPROCS</code> 个线程分布在多个 CPU 上执行</p><h3 id="抢占" tabindex="-1"><a class="header-anchor" href="#抢占" aria-hidden="true">#</a> 抢占</h3><p>在 coroutine 中要等待一个协程主动让出 CPU 才执行下一个协程</p><p>在 Go 中，一个 goroutine 最多占用 CPU 10ms，防止其他 goroutine 被饿死</p><h2 id="调度过程" tabindex="-1"><a class="header-anchor" href="#调度过程" aria-hidden="true">#</a> 调度过程</h2><p><img src="'+l+'" alt="Alt text"></p><h2 id="调度器生命周期" tabindex="-1"><a class="header-anchor" href="#调度器生命周期" aria-hidden="true">#</a> 调度器生命周期</h2><ul><li><p>M0</p><ul><li>程序启动后编号为0的主线程</li><li>负责初始化操作和启动第一个 G</li></ul></li><li><p>G0</p><ul><li>每次启动一个 M, 都会先创建 G0, 每个 M 都会有一个自己的 G0</li><li>负责调度 G, 在调度或系统调用时会使用 G0 的栈空间</li></ul></li></ul><p><img src="'+o+'" alt="Alt text"></p>',17),h=[d];function n(c,p){return a(),i("div",null,h)}const m=e(s,[["render",n],["__file","gmp.html.vue"]]);export{m as default};
